import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  IconButton,
  Tooltip,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  Close,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  const loadFinishedPositions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await dashboardService.getFinishedPositions();
      console.log('Posições finalizadas:', response); // Debug
      if (response.success) {
        setPositions(response.positions || []);
      } else {
        setError(response.message || 'Erro ao carregar posições');
      }
    } catch (err) {
      console.error('Erro ao carregar posições finalizadas:', err);
      setError('Erro ao carregar posições finalizadas');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return '-';
    return new Date(parseInt(timestamp)).toLocaleString();
  };

  const formatValue = (value) => {
    if (value === undefined || value === null || value === '') return '-';
    if (typeof value === 'string') {
      const numValue = parseFloat(value);
      if (isNaN(numValue)) return value;
      return numValue.toFixed(4);
    }
    return value.toFixed(4);
  };

  const formatCurrency = (value, currency = 'USDT') => {
    if (hideValues) return `*** ${currency}`;
    const numValue = parseFloat(value || 0);

    if (Math.abs(numValue) < 0.001 && numValue !== 0) {
      return `${numValue.toFixed(8)} ${currency}`;
    }

    if (Math.abs(numValue) < 0.1 && numValue !== 0) {
      return `${numValue.toFixed(6)} ${currency}`;
    }

    if (Math.abs(numValue) < 1) {
      return `${numValue.toFixed(4)} ${currency}`;
    }

    return `${numValue.toFixed(4)} ${currency}`;
  };

  const getColorByValue = (value) => {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  };

  const getSideColor = (side) => {
    return side === 'long' ? '#02c076' : '#f84960';
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="lg"
      fullWidth
    >
      <DialogTitle>
        <Box display="flex" justifyContent="space-between" alignItems="center">
          <Typography variant="h6">Operações Finalizadas</Typography>
          <Box>
            <Tooltip title="Atualizar">
              <IconButton onClick={handleRefresh} disabled={refreshing}>
                <Refresh />
              </IconButton>
            </Tooltip>
            <Tooltip title="Fechar">
              <IconButton onClick={onClose}>
                <Close />
              </IconButton>
            </Tooltip>
          </Box>
        </Box>
      </DialogTitle>
      <DialogContent>
        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}
        {loading ? (
          <Box display="flex" justifyContent="center" p={3}>
            <CircularProgress />
          </Box>
        ) : (
          <TableContainer component={Paper}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Par</TableCell>
                  <TableCell>Lado</TableCell>
                  <TableCell>Tamanho</TableCell>
                  <TableCell>Alavancagem</TableCell>
                  <TableCell>Preço Médio</TableCell>
                  <TableCell>Take Profit</TableCell>
                  <TableCell>Stop Loss</TableCell>
                  <TableCell>Lucro/Prejuízo</TableCell>
                  <TableCell>Data Criação</TableCell>
                  <TableCell>Data Fechamento</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.map((position, index) => (
                  <TableRow key={`${position.symbol}-${position.cTime}-${index}`}>
                    <TableCell>{position.symbol || '-'}</TableCell>
                    <TableCell>{position.holdSide || '-'}</TableCell>
                    <TableCell>{formatValue(position.openDelegateSize)}</TableCell>
                    <TableCell>{position.leverage ? `${position.leverage}x` : '-'}</TableCell>
                    <TableCell>{formatValue(position.openPriceAvg)}</TableCell>
                    <TableCell>{formatValue(position.takeProfit)}</TableCell>
                    <TableCell>{formatValue(position.stopLoss)}</TableCell>
                    <TableCell>{formatValue(position.achievedProfits)}</TableCell>
                    <TableCell>{formatDate(position.cTime)}</TableCell>
                    <TableCell>{formatDate(position.uTime)}</TableCell>
                  </TableRow>
                ))}
                {positions.length === 0 && (
                  <TableRow>
                    <TableCell colSpan={10} align="center">
                      Nenhuma operação finalizada encontrada
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
